package kotlinx.datetime

import kotlin.test.Test
import kotlin.test.assertEquals

class LocalDateParseTest {
    @Test
    fun testParseWithManyLeadingZeros() {
        val s = "+00000000000002022-07-16"
        val date = LocalDate.parse(s)
        assertEquals(2022, date.year)
        assertEquals(7, date.monthNumber)
        assertEquals(16, date.dayOfMonth)
    }

    @Test
    fun testLocalDateTimeParseWithManyLeadingZeros() {
        val s = "+00000000000002022-07-16T12:00:00"
        val dateTime = LocalDateTime.parse(s)
        assertEquals(2022, dateTime.year)
        assertEquals(7, dateTime.monthNumber)
        assertEquals(16, dateTime.dayOfMonth)
    }
}
"}

